UPDATE reliability SET
  common_failures = '["valve_cover_gasket","water_pump","oil_filter_housing_gasket","disa_valve","window_regulators","vanos_solenoid"]',
  known_issues = '["n52_valve_cover: Oil weep from valve cover gasket at 60-120K miles. Early magnesium covers (pre-2007) more durable; post-2007 plastic covers crack. 400-600 shop, ~150 DIY","electric_water_pump: Fails WITHOUT WARNING at 60-100K miles. No serpentine belt drive. Sudden overheating triggers limp mode. Replace preventively at 80-100K with thermostat. 600-800 total","oil_filter_housing_gasket: OFHG leak at 60-120K. CRITICAL: leaking oil on serpentine belt can cause belt to slip off and get sucked into crank seal, destroying engine. Do not ignore. 500-700 shop, ~80 DIY","disa_valve: Intake manifold flap actuator failure at 80-120K. Rough idle, CEL, loss of low-end torque. 200-400 per valve","hydraulic_lifter_tick: Pre-November 2008 N52 engines prone to cold-start ticking. Post-Nov 2008 engines resolved","window_regulators: E90 chassis-wide issue. Cable mechanism fails, window slides down into door. 200-400 per window","vanos_solenoid: Dirty oil clogs solenoid screens. Clean oil changes prevent this. 200-400 cleaning, 400-600 replacement","timing_chain: Uses chain not belt. Generally robust unlike N20. Guide rails can break at 120K+ miles. Preventive replacement around 150K. 1500-3000 if needed","oil_consumption: Up to 1qt per 1000-1500 miles is within BMW normal spec. Well-maintained N52s typically 0.5-1qt per 3000-5000 miles"]',
  score_notes = '["engine: N52 is one of BMW most reliable engines. Wards 10 Best 2006-2007. Magnesium/aluminum composite block was groundbreaking. Known issues are predictable and manageable. The failure modes help the appreciation thesis: less and less of them available","transmission: ZF 6-speed manual is excellent. One of the best manual transmissions BMW ever made","chassis: E90 chassis is well-engineered. RWD, near 50/50 weight distribution. Subframe issue from E46 largely resolved","electronics: iDrive CCC system ages poorly. Window regulators fail across the E90 range. Generally less reliable than Japanese competitors","ease_of_repair: N52 is one of the easier BMW engines to work on. Large DIY community. Most major services are weekend jobs"]'
WHERE car_id = 37;
